# Problem: Build an OpenAPI/Swagger specification generator that documents versioned API endpoints.
#
# Approach:
# - SchemaGenerator introspects Pydantic model_fields to map Python types to JSON Schema types.
# - EndpointDoc is a Pydantic model holding metadata for a single endpoint.
# - APIVersion groups endpoints under a version string and prefix.
# - OpenAPIGenerator assembles the full OpenAPI 3.0.0 spec, with optional version filtering.
# - build_user_api_docs constructs a sample API with v1 and v2 endpoints.
#
# Time complexity: O(n) where n is total endpoints across all versions.
# Space complexity: O(n) for storing endpoints and the generated spec.
#
# Key steps:
# 1. Implement SchemaGenerator.from_model using model_fields and annotation introspection.
# 2. Define EndpointDoc as a Pydantic BaseModel with all required fields.
# 3. Implement APIVersion to store and retrieve endpoints.
# 4. Implement OpenAPIGenerator to assemble paths, tags, and the full spec.
# 5. Implement build_user_api_docs with v1 (3 endpoints) and v2 (4 endpoints, one deprecated).

from pydantic import BaseModel
from typing import Any, Optional, get_origin, get_args, Union
import types


class SchemaGenerator:

    TYPE_MAP = {
        'str': 'string',
        'int': 'integer',
        'float': 'number',
        'bool': 'boolean',
        'list': 'array',
    }

    @classmethod
    def from_model(cls, model_cls) -> dict:
        properties = {}
        required = []

        for field_name, field_info in model_cls.model_fields.items():
            annotation = field_info.annotation
            field_schema = cls._resolve_type(annotation)
            properties[field_name] = field_schema

            # A field is required if it has no default and isn't nullable
            if field_info.default is None and field_schema.get('nullable'):
                pass  # Optional fields are not required
            elif field_info.is_required():
                required.append(field_name)

        schema = {
            'type': 'object',
            'properties': properties,
        }
        if required:
            schema['required'] = required
        return schema

    @classmethod
    def _resolve_type(cls, annotation) -> dict:
        # Handle None type
        if annotation is type(None):
            return {'nullable': True}

        # Handle Optional[X] (Union[X, None]) and X | None
        origin = get_origin(annotation)
        if origin is Union or origin is types.UnionType:
            args = get_args(annotation)
            non_none = [a for a in args if a is not type(None)]
            if non_none:
                schema = cls._resolve_type(non_none[0])
                if type(None) in args:
                    schema['nullable'] = True
                return schema
            return {'nullable': True}

        # Handle list[X] — generic list with inner type
        if origin is list:
            inner_args = get_args(annotation)
            schema = {'type': 'array'}
            if inner_args:
                schema['items'] = cls._resolve_type(inner_args[0])
            return schema

        # Handle basic types by __name__
        type_name = getattr(annotation, '__name__', str(annotation))
        if type_name in cls.TYPE_MAP:
            return {'type': cls.TYPE_MAP[type_name]}

        return {'type': 'string'}


class EndpointDoc(BaseModel):
    method: str
    path: str
    summary: str
    description: str = ''
    tags: list[str] = []
    request_body: dict | None = None
    response_schema: dict | None = None
    parameters: list[dict] = []
    deprecated: bool = False


class APIVersion:
    def __init__(self, version: str, prefix: str):
        self.version = version
        self.prefix = prefix
        self._endpoints: list[EndpointDoc] = []

    def add_endpoint(self, endpoint: EndpointDoc) -> None:
        self._endpoints.append(endpoint)

    def get_endpoints(self) -> list[EndpointDoc]:
        return list(self._endpoints)


class OpenAPIGenerator:
    def __init__(self, title: str, description: str = '',
                 versions: list[APIVersion] | None = None):
        self.title = title
        self.description = description
        self._versions: list[APIVersion] = versions or []

    def add_version(self, version: APIVersion) -> None:
        self._versions.append(version)

    def generate_spec(self, version: str | None = None) -> dict:
        if version is not None:
            selected = [v for v in self._versions if v.version == version]
        else:
            selected = self._versions

        spec_version = version if version else (
            self._versions[-1].version if self._versions else '1.0'
        )

        # Group endpoints under path -> method
        paths: dict[str, dict] = {}
        all_tags: set[str] = set()

        for api_ver in selected:
            for ep in api_ver.get_endpoints():
                full_path = api_ver.prefix + ep.path  # e.g. "/api/v1" + "/users"
                if full_path not in paths:
                    paths[full_path] = {}

                operation: dict[str, Any] = {'summary': ep.summary}
                if ep.description:
                    operation['description'] = ep.description
                if ep.tags:
                    operation['tags'] = ep.tags
                    all_tags.update(ep.tags)
                if ep.parameters:
                    operation['parameters'] = ep.parameters
                if ep.request_body:
                    # OpenAPI 3.0 wraps schema in content/application/json
                    operation['requestBody'] = {
                        'content': {
                            'application/json': {'schema': ep.request_body}
                        }
                    }
                if ep.deprecated:
                    operation['deprecated'] = True

                # Build responses
                resp: dict[str, Any] = {'description': 'Successful response'}
                if ep.response_schema:
                    resp['content'] = {
                        'application/json': {'schema': ep.response_schema}
                    }
                operation['responses'] = {'200': resp}

                paths[full_path][ep.method.lower()] = operation

        tags_list = [{'name': t, 'description': ''} for t in sorted(all_tags)]

        return {
            'openapi': '3.0.0',
            'info': {
                'title': self.title,
                'description': self.description,
                'version': spec_version,
            },
            'paths': paths,
            'tags': tags_list,
        }

    def get_all_tags(self) -> list[str]:
        tags: set[str] = set()
        for api_ver in self._versions:
            for ep in api_ver.get_endpoints():
                tags.update(ep.tags)
        return sorted(tags)


def build_user_api_docs() -> OpenAPIGenerator:
    # v1: three basic user endpoints
    v1 = APIVersion(version='1.0', prefix='/api/v1')
    v1.add_endpoint(EndpointDoc(
        method='GET', path='/users',
        summary='List users', tags=['users']
    ))
    v1.add_endpoint(EndpointDoc(
        method='POST', path='/users',
        summary='Create user', tags=['users']
    ))
    v1.add_endpoint(EndpointDoc(
        method='GET', path='/users/{id}',
        summary='Get user', tags=['users'],
        parameters=[{'name': 'id', 'in': 'path', 'required': True,
                      'schema': {'type': 'integer'}}]
    ))

    # v2: same three plus search, with get-by-id deprecated
    v2 = APIVersion(version='2.0', prefix='/api/v2')
    v2.add_endpoint(EndpointDoc(
        method='GET', path='/users',
        summary='List users', tags=['users']
    ))
    v2.add_endpoint(EndpointDoc(
        method='POST', path='/users',
        summary='Create user', tags=['users']
    ))
    v2.add_endpoint(EndpointDoc(
        method='GET', path='/users/{id}',
        summary='Get user', tags=['users'],
        parameters=[{'name': 'id', 'in': 'path', 'required': True,
                      'schema': {'type': 'integer'}}],
        deprecated=True
    ))
    v2.add_endpoint(EndpointDoc(
        method='GET', path='/users/search',
        summary='Search users', tags=['users', 'search']
    ))

    return OpenAPIGenerator(
        title='User API',
        description='API for managing users',
        versions=[v1, v2]
    )
